parameters.jsCode:
const resp = $input.first().json;
const content = resp.choices?.[0]?.message?.content ?? resp.message?.content ?? '5';
const score = Math.min(10, Math.max(1, parseInt(String(content).match(/\d+/)?.[0] || '5') || 5));
let lead = {};
try { lead = $('Normalize Lead Data').first().json; } catch (_) {}
if (!lead || Object.keys(lead).length === 0) { try { lead = $('Sample Data').first().json; } catch (_) {} }
const threshold = lead.SCORE_THRESHOLD ?? 7;
return { json: { ...lead, score, status: score >= threshold ? 'hot' : 'nurture', action: score >= threshold ? 'immediate_followup' : 'add_to_sequence', processed: true } };
